    /* AAD */
    poly1305_update(&mac_ctx, aad, aad_len);
    pad16(&mac_ctx, aad_len);

    /* Ciphertext */
    poly1305_update(&mac_ctx, ciphertext, pt_len);
    pad16(&mac_ctx, pt_len);

    /* Lengths (little-endian 64-bit) */
