    poly1305_update(&mac_ctx, aad, aad_len);
    pad16(&mac_ctx, aad_len);
    poly1305_update(&mac_ctx, ciphertext, ct_len);
    pad16(&mac_ctx, ct_len);

    memset(len_block, 0, sizeof(len_block));
    store32_le(len_block + 0, (uint32_t)aad_len);
    store32_le(len_block + 4, (uint32_t)(aad_len >> 32));
    store32_le(len_block + 8, (uint32_t)ct_len);
    store32_le(len_block + 12, (uint32_t)(ct_len >> 32));
