/* ============== IoT Sensor Data Packet Helpers ============== */

/* Maximum sensor payload size for constrained devices */
#define IOT_MAX_PAYLOAD_SIZE    256
#define IOT_NONCE_SIZE          12
#define IOT_TAG_SIZE            16
#define IOT_KEY_SIZE            32
#define IOT_DEVICE_ID_SIZE      4

/*
 * Encrypted packet format:
 * [device_id: 4B][nonce: 12B][ciphertext: N bytes][tag: 16B]
 *
 * device_id and nonce are authenticated but not encrypted (AAD).
 */
typedef struct __attribute__((packed)) {
    uint8_t  device_id[IOT_DEVICE_ID_SIZE];
    uint8_t  nonce[IOT_NONCE_SIZE];
    uint8_t  payload[IOT_MAX_PAYLOAD_SIZE + IOT_TAG_SIZE];
    uint16_t payload_len; /* ciphertext length (excluding tag) */
} iot_packet_t;

/*
 * Simple nonce counter - MUST be persisted to non-volatile storage
 * to prevent nonce reuse across reboots.
 */
typedef struct {
    uint32_t counter_high;
    uint32_t counter_low;
    uint8_t  device_id[IOT_DEVICE_ID_SIZE];
} iot_nonce_state_t;

static void iot_generate_nonce(iot_nonce_state_t *state, uint8_t nonce[12])
{
    /* Nonce = device_id(4) || counter_high(4) || counter_low(4) */
    memcpy(nonce, state->device_id, 4);
    store32_le(nonce + 4, state->counter_high);
    store32_le(nonce + 8, state->counter_low);

    /* Increment 64-bit counter */
    state->counter_low++;
    if (state->counter_low == 0) {
        state->counter_high++;
    }
}

/*
 * Encrypt sensor data into a transmit-ready packet.
 *
 * Parameters:
 *   key          - Pre-shared 256-bit device key
 *   nonce_state  - Nonce counter state (caller must persist to NVM)
 *   sensor_data  - Raw sensor readings
 *   data_len     - Length of sensor data
 *   packet       - Output packet ready for transmission
 *
 * Returns: total packet size on success, -1 on error
 */
int iot_sensor_encrypt_packet(const uint8_t key[IOT_KEY_SIZE],
                              iot_nonce_state_t *nonce_state,
                              const uint8_t *sensor_data,
                              size_t data_len,
                              iot_packet_t *packet)
{
    uint8_t aad[IOT_DEVICE_ID_SIZE + IOT_NONCE_SIZE];

    if (data_len > IOT_MAX_PAYLOAD_SIZE || data_len == 0) {
        return -1;
    }

    /* Set device ID */
    memcpy(packet->device_id, nonce_state->device_id, IOT_DEVICE_ID_SIZE);

    /* Generate unique nonce */
    iot_generate_nonce(nonce_state, packet->nonce);

    /* Build AAD: device_id || nonce */
    memcpy(aad, packet->device_id, IOT_DEVICE_ID_SIZE);
    memcpy(aad + IOT_DEVICE_ID_SIZE, packet->nonce, IOT_NONCE_SIZE);

    /* Encrypt and authenticate */
    iot_encrypt(key, packet->nonce,
                aad, sizeof(aad),
                sensor_data, data_len,
                packet->payload,
                packet->payload + data_len); /* Tag appended after ciphertext */

    packet->payload_len = (uint16_t)data_len;

    /* Total wire size: device_id + nonce + ciphertext + tag */
    return (int)(IOT_DEVICE_ID_SIZE + IOT_NONCE_SIZE + data_len + IOT_TAG_SIZE);
}

/*
 * Decrypt and verify a received packet (cloud-side or device-side).
 *
 * Returns: plaintext length on success, -1 on authentication failure
 */
int iot_sensor_decrypt_packet(const uint8_t key[IOT_KEY_SIZE],
                              const iot_packet_t *packet,
                              uint8_t *sensor_data,
                              size_t max_data_len)
{
    uint8_t aad[IOT_DEVICE_ID_SIZE + IOT_NONCE_SIZE];
    int ret;

    if (packet->payload_len > IOT_MAX_PAYLOAD_SIZE ||
        packet->payload_len == 0 ||
        packet->payload_len > max_data_len) {
        return -1;
    }

    /* Reconstruct AAD */
    memcpy(aad, packet->device_id, IOT_DEVICE_ID_SIZE);
    memcpy(aad + IOT_DEVICE_ID_SIZE, packet->nonce, IOT_NONCE_SIZE);

    /* Decrypt and verify */
    ret = iot_decrypt(key, packet->nonce,
                      aad, sizeof(aad),
                      packet->payload, packet->payload_len,
                      packet->payload + packet->payload_len, /* Tag location */
                      sensor_data);

    if (ret != 0) {
        return -1;
    }

    return (int)packet->payload_len;
}

